#!/usr/bin/env node
/**
 * Generate llms-full.txt by concatenating all curated docs + token JSON + component specs.
 *
 * Walks a fixed set of directories with explicit per-extension handlers. New file types
 * require an explicit handler addition here — no implicit globs.
 *
 * Output is gitignored; regenerated by `pnpm run build-llms-full`.
 */

import { existsSync, readFileSync, readdirSync, statSync, writeFileSync } from 'node:fs';
import { dirname, extname, join, relative } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = join(__dirname, '..');
const OUT = join(ROOT, 'llms-full.txt');

const SOURCES = [
  { dir: 'foundations', exts: ['.md'] },
  { dir: 'tokens', exts: ['.json'] },
  { dir: 'components', exts: ['.md', '.json'] },
  { dir: 'patterns', exts: ['.md', '.json'] },
];

const HANDLERS = {
  '.md': (rel, content) => `\n\n<!-- FILE: ${rel} -->\n${content}`,
  '.json': (rel, content) =>
    `\n\n<!-- FILE: ${rel} (DTCG JSON) -->\n\`\`\`json\n${content}\n\`\`\``,
};

function walk(dir) {
  const out = [];
  if (!existsSync(dir)) return out;
  for (const entry of readdirSync(dir)) {
    const full = join(dir, entry);
    const st = statSync(full);
    if (st.isDirectory()) {
      out.push(...walk(full));
    } else {
      out.push(full);
    }
  }
  return out;
}

function build() {
  const header = [
    '# os-hcl-design — full context',
    '',
    '> Generated by scripts/build-llms-full.mjs. Do not edit.',
    '> Regenerate via `pnpm run build-llms-full`.',
    '',
    'This file concatenates every foundation doc, token JSON, component/pattern spec, and component/pattern doc into one long Markdown stream for LLM consumers that can ingest wide context in a single call. For retrieval-by-link, use [llms.txt](./llms.txt) instead.',
    '',
  ].join('\n');

  let body = '';
  for (const { dir, exts } of SOURCES) {
    const abs = join(ROOT, dir);
    const files = walk(abs)
      .filter((f) => exts.includes(extname(f)))
      .sort();
    for (const f of files) {
      const rel = relative(ROOT, f);
      const ext = extname(f);
      const handler = HANDLERS[ext];
      if (!handler) {
        throw new Error(`No handler for extension ${ext} (file: ${rel})`);
      }
      const content = readFileSync(f, 'utf8');
      body += handler(rel, content);
    }
  }

  writeFileSync(OUT, header + body + '\n', 'utf8');
  console.log(`✓ Wrote ${OUT}`);
  console.log(`  size: ${(readFileSync(OUT).length / 1024).toFixed(1)} KB`);
}

build();
